export const onRequest: PagesFunction<Env> = async (ctx) => {
  const host = ctx.request.headers.get('host') ?? ''
  const tenant = await ctx.env.DB.prepare('SELECT * FROM tenants WHERE domain = ?').bind(host).first<Tenant>()
  if (!tenant || tenant.status === 'frozen') return new Response('Not found', { status: 404 })
  ctx.data.tenant = tenant
  return ctx.next()
}

function renderThemeStyleTag(theme: ThemeJSON): string {
  const vars = Object.entries(theme).filter(([k]) => k.startsWith('--'))
  return `<style>:root{${vars.map(([k,v]) => `${k}:${v}`).join(';')}}</style>`
}

